+            let min = glue.natural_subcell.saturating_sub(glue.shrink_subcell);
+            let max = glue.natural_subcell.saturating_add(glue.stretch_subcell);
+            assert!(
+                w1 >= min && w1 <= max,
+                "adjusted_width out of range for glue={} ratio={}: {} not in [{}, {}]",
+                name,
+                ratio,
+                w1,
+                min,
+                max
+            );
+        }
+    }
