+#[test]
+fn degradation_chain_snapshot() {
+    // Start at Quality and degrade through the full chain.
+    let mut tier = LayoutTier::Quality;
+    let mut chain = vec![tier];
+
+    while let Some(next) = tier.degrade() {
+        chain.push(next);
+        tier = next;
+    }
+
+    assert_eq!(
+        chain,
+        vec![
+            LayoutTier::Quality,
+            LayoutTier::Balanced,
+            LayoutTier::Fast,
+            LayoutTier::Emergency,
